class SEWDGroupNormConvLayer(GradientCheckpointingLayer) {
  __init__(config, layer_id=0) {
    in_dim = config.conv_dim[layer_id-1] if layer_id>0 else 1
    out_dim = config.conv_dim[layer_id]
    conv = nn.Conv1d(in_dim, out_dim, kernel=config.conv_kernel[layer_id], stride=config.conv_stride[layer_id], bias=config.conv_bias)
    activation = ACT2FN[config.feat_extract_activation]
    norm = nn.GroupNorm(num_groups=out_dim, num_channels=out_dim, affine=True)
  }
  forward(hidden_states) = conv -> norm -> activation -> hidden_states
}
